"use client";

/**
 * <CancelDialog /> — two-step cancellation flow with retention offer.
 *
 * Forked from billingsdk's cancel-subscription-dialog (MIT). Theme-context
 * dependency stripped — uses default shadcn tokens.
 */
import { useState, useEffect } from "react";
import { Button } from "@dollhousestudio/ui/components/button";
import { Badge } from "@dollhousestudio/ui/components/badge";
import {
  Dialog,
  DialogClose,
  DialogContent,
  DialogTitle,
  DialogTrigger,
} from "@dollhousestudio/ui/components/dialog";
import { X, Circle } from "lucide-react";
import { cn } from "@dollhousestudio/ui/lib/utils";
import type { Plan } from "../lib/billing-transformers";

export interface CancelDialogProps {
  title?: string;
  description?: string;
  plan: Plan;
  triggerButtonText?: string;
  warningTitle?: string;
  warningText?: string;
  keepButtonText?: string;
  continueButtonText?: string;
  finalTitle?: string;
  finalSubtitle?: string;
  finalWarningText?: string;
  goBackButtonText?: string;
  confirmButtonText?: string;
  onCancel: (planId: string) => Promise<void> | void;
  onKeepSubscription?: (planId: string) => Promise<void> | void;
  onDialogClose?: () => void;
  className?: string;
}

export function CancelDialog({
  title = "We're sorry to see you go",
  description = "Before you cancel, we hope you'll consider staying with us.",
  plan,
  triggerButtonText = "Cancel subscription",
  warningTitle,
  warningText,
  keepButtonText = "Keep subscription",
  continueButtonText = "Continue cancellation",
  finalTitle = "Final confirmation",
  finalSubtitle = "Are you sure you want to cancel?",
  finalWarningText = "This action cannot be undone and you'll lose access at period end.",
  goBackButtonText = "Go back",
  confirmButtonText = "Yes, cancel subscription",
  onCancel,
  onKeepSubscription,
  onDialogClose,
  className,
}: CancelDialogProps) {
  const [showConfirmation, setShowConfirmation] = useState(false);
  const [isOpen, setIsOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleDialogClose = () => {
    setIsOpen(false);
    setShowConfirmation(false);
    setError(null);
    setIsLoading(false);
    onDialogClose?.();
  };

  const handleContinue = () => {
    setShowConfirmation(true);
    setError(null);
  };

  const handleKeep = async () => {
    try {
      setIsLoading(true);
      setError(null);
      if (onKeepSubscription) await onKeepSubscription(plan.id);
      handleDialogClose();
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed");
    } finally {
      setIsLoading(false);
    }
  };

  const handleConfirm = async () => {
    try {
      setIsLoading(true);
      setError(null);
      await onCancel(plan.id);
      handleDialogClose();
    } catch (err) {
      setError(
        err instanceof Error ? err.message : "Failed to cancel subscription",
      );
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (isOpen && e.key === "Escape") {
        e.preventDefault();
        handleDialogClose();
      }
    };
    document.addEventListener("keydown", onKey);
    return () => document.removeEventListener("keydown", onKey);
  }, [isOpen]);

  return (
    <Dialog
      open={isOpen}
      onOpenChange={(open) => {
        if (open) setIsOpen(true);
        else handleDialogClose();
      }}
    >
      <DialogTrigger asChild>
        <Button variant="outline">{triggerButtonText}</Button>
      </DialogTrigger>
      <DialogContent
        className={cn(
          "flex w-[95%] flex-col overflow-hidden p-0 sm:max-w-[500px]",
          className,
        )}
      >
        <DialogTitle className="sr-only">{title}</DialogTitle>
        <DialogClose
          onClick={handleDialogClose}
          className="absolute right-4 top-4 z-10 rounded-sm opacity-70 transition-opacity hover:opacity-100"
        >
          <X className="h-4 w-4" />
          <span className="sr-only">Close</span>
        </DialogClose>

        <div className="flex w-full flex-col gap-4 px-4 py-6">
          <div className="flex flex-col gap-2 text-center md:text-left">
            <h2 className="text-xl font-semibold md:text-2xl">{title}</h2>
            <p className="text-xs text-muted-foreground md:text-sm">
              {description}
            </p>
            {error && (
              <div className="rounded-md border border-destructive/20 bg-destructive/10 p-3 text-sm text-destructive">
                {error}
              </div>
            )}
          </div>

          {!showConfirmation && (
            <div className="flex flex-col gap-4 rounded-lg bg-muted/50 p-4">
              <div className="flex items-center justify-between">
                <div className="flex flex-col gap-1">
                  <span className="text-lg font-semibold">
                    {plan.title} plan
                  </span>
                  <span className="text-sm text-muted-foreground">
                    Current subscription
                  </span>
                </div>
                <Badge variant="secondary">
                  {plan.currency}
                  {plan.monthlyPrice}/mo
                </Badge>
              </div>
              <div className="flex flex-col gap-2">
                {plan.features.slice(0, 4).map((f, i) => (
                  <div key={i} className="flex items-center gap-2">
                    <Circle className="h-2 w-2 fill-primary text-primary" />
                    <span className="text-sm text-muted-foreground">
                      {f.name}
                    </span>
                  </div>
                ))}
              </div>
            </div>
          )}

          {!showConfirmation && (warningTitle || warningText) && (
            <div className="rounded-lg border bg-muted/30 p-4">
              {warningTitle && (
                <h3 className="mb-2 font-semibold">{warningTitle}</h3>
              )}
              {warningText && (
                <p className="text-sm text-muted-foreground">{warningText}</p>
              )}
            </div>
          )}

          {!showConfirmation ? (
            <div className="mt-auto flex flex-col gap-3 sm:flex-row">
              <Button
                className="flex-1"
                onClick={handleKeep}
                disabled={isLoading}
              >
                {isLoading ? "Processing…" : keepButtonText}
              </Button>
              <Button
                variant="destructive"
                className="flex-1"
                onClick={handleContinue}
                disabled={isLoading}
              >
                {continueButtonText}
              </Button>
            </div>
          ) : (
            <div className="mt-auto flex flex-col gap-4">
              <div className="rounded-lg bg-muted/50 p-4 text-center">
                <h3 className="mb-2 font-semibold">{finalTitle}</h3>
                <p className="mb-2 text-sm text-muted-foreground">
                  {finalSubtitle}
                </p>
                <p className="text-sm text-destructive">{finalWarningText}</p>
              </div>
              <div className="flex flex-col gap-3 sm:flex-row">
                <Button
                  variant="outline"
                  className="flex-1"
                  onClick={() => setShowConfirmation(false)}
                  disabled={isLoading}
                >
                  {goBackButtonText}
                </Button>
                <Button
                  variant="destructive"
                  className="flex-1"
                  onClick={handleConfirm}
                  disabled={isLoading}
                >
                  {isLoading ? "Cancelling…" : confirmButtonText}
                </Button>
              </div>
            </div>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

"use client";

/**
 * <CheckoutButton /> — one-shot button that opens a Stripe Checkout session.
 *
 * Pass either a Parcae Price ID (`price`) or a Stripe price ID (`priceId`).
 * On click, it calls POST /v1/billing/checkout and redirects.
 */
import { useState } from "react";
import { Button } from "@dollhousestudio/ui/components/button";
import { Loader2 } from "lucide-react";
import { useBilling } from "../hooks/use-billing";

export interface CheckoutButtonProps {
  /** Parcae Price ID (preferred). */
  price?: string;
  /** Stripe price ID alternative. */
  priceId?: string;
  quantity?: number;
  successUrl?: string;
  cancelUrl?: string;
  promotionCode?: string;
  metadata?: Record<string, string>;
  children?: React.ReactNode;
  className?: string;
  variant?:
    | "default"
    | "destructive"
    | "outline"
    | "secondary"
    | "ghost"
    | "link";
  size?: "default" | "sm" | "lg" | "icon";
  disabled?: boolean;
}

export function CheckoutButton({
  price,
  priceId,
  quantity,
  successUrl,
  cancelUrl,
  promotionCode,
  metadata,
  children = "Subscribe",
  className,
  variant = "default",
  size = "default",
  disabled,
}: CheckoutButtonProps) {
  const { openCheckout } = useBilling();
  const [pending, setPending] = useState(false);

  async function handleClick() {
    if (!price && !priceId) return;
    setPending(true);
    try {
      await openCheckout({
        price,
        priceId,
        quantity,
        successUrl,
        cancelUrl,
        promotionCode,
        metadata,
      });
    } catch (err) {
      console.error("[billing] Checkout failed:", err);
      setPending(false);
    }
  }

  return (
    <Button
      className={className}
      variant={variant}
      size={size}
      disabled={disabled || pending}
      onClick={handleClick}
    >
      {pending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
      {children}
    </Button>
  );
}

"use client";

/**
 * <CustomerPortalButton /> — opens the Stripe Customer Portal.
 *
 * Delegates most billing UX (card management, invoices, cancellation) to
 * Stripe's hosted portal so you don't have to build it.
 */
import { useState } from "react";
import { Button } from "@dollhousestudio/ui/components/button";
import { Loader2, ExternalLink } from "lucide-react";
import { useBilling } from "../hooks/use-billing";

export interface CustomerPortalButtonProps {
  returnUrl?: string;
  children?: React.ReactNode;
  className?: string;
  variant?:
    | "default"
    | "destructive"
    | "outline"
    | "secondary"
    | "ghost"
    | "link";
  size?: "default" | "sm" | "lg" | "icon";
  /** If false, show label without the external-link icon. */
  showIcon?: boolean;
  disabled?: boolean;
}

export function CustomerPortalButton({
  returnUrl,
  children = "Manage billing",
  className,
  variant = "outline",
  size = "default",
  showIcon = true,
  disabled,
}: CustomerPortalButtonProps) {
  const { openPortal } = useBilling();
  const [pending, setPending] = useState(false);

  async function handleClick() {
    setPending(true);
    try {
      await openPortal(returnUrl);
    } catch (err) {
      console.error("[billing] Portal failed:", err);
      setPending(false);
    }
  }

  return (
    <Button
      className={className}
      variant={variant}
      size={size}
      disabled={disabled || pending}
      onClick={handleClick}
    >
      {pending ? (
        <Loader2 className="mr-2 h-4 w-4 animate-spin" />
      ) : showIcon ? (
        <ExternalLink className="mr-2 h-4 w-4" />
      ) : null}
      {children}
    </Button>
  );
}

"use client";

/**
 * <InvoiceList /> — paginated invoice history.
 *
 * Forked from billingsdk's invoice-history (MIT). Binds to Parcae's
 * `Invoice` model via `useQuery`.
 */
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@dollhousestudio/ui/components/card";
import {
  Table,
  TableBody,
  TableCaption,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@dollhousestudio/ui/components/table";
import { Badge } from "@dollhousestudio/ui/components/badge";
import { Button } from "@dollhousestudio/ui/components/button";
import { cn } from "@dollhousestudio/ui/lib/utils";
import { CalendarDays, Download, ReceiptText } from "lucide-react";
import type { InvoiceItem } from "../lib/billing-transformers";

export interface InvoiceListProps {
  invoices: InvoiceItem[];
  className?: string;
  title?: string;
  description?: string;
  loading?: boolean;
  onDownload?: (invoiceId: string) => void;
}

function statusBadge(status: InvoiceItem["status"]) {
  switch (status) {
    case "paid":
      return (
        <Badge className="border-emerald-700/40 bg-emerald-600 text-emerald-50">
          Paid
        </Badge>
      );
    case "refunded":
      return <Badge variant="secondary">Refunded</Badge>;
    case "open":
      return <Badge variant="outline">Open</Badge>;
    case "void":
      return <Badge variant="outline">Void</Badge>;
  }
}

export function InvoiceList({
  invoices,
  className,
  title = "Invoice history",
  description = "Your past invoices and payment receipts.",
  loading,
  onDownload,
}: InvoiceListProps) {
  return (
    <Card className={cn("w-full", className)}>
      {(title || description) && (
        <CardHeader className="space-y-1">
          <CardTitle className="flex items-center gap-2 text-lg font-medium">
            <ReceiptText className="h-4 w-4 text-primary" />
            {title}
          </CardTitle>
          {description && (
            <CardDescription className="text-sm text-muted-foreground">
              {description}
            </CardDescription>
          )}
        </CardHeader>
      )}
      <CardContent>
        <Table>
          <TableCaption className="sr-only">
            List of past invoices with dates, amounts, status, and download
            actions.
          </TableCaption>
          <TableHeader>
            <TableRow>
              <TableHead className="w-[120px]">Date</TableHead>
              <TableHead>Description</TableHead>
              <TableHead className="text-right">Amount</TableHead>
              <TableHead className="text-right">Status</TableHead>
              <TableHead className="text-right">Action</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {(loading || !invoices || invoices.length === 0) && (
              <TableRow>
                <TableCell
                  colSpan={5}
                  className="h-24 text-center text-muted-foreground"
                >
                  {loading ? "Loading…" : "No invoices yet"}
                </TableCell>
              </TableRow>
            )}
            {invoices?.map((inv) => (
              <TableRow key={inv.id} className="group">
                <TableCell className="text-muted-foreground">
                  <div className="inline-flex items-center gap-2">
                    <CalendarDays className="h-3.5 w-3.5" />
                    {inv.date}
                  </div>
                </TableCell>
                <TableCell className="max-w-[320px]">
                  <div
                    className="truncate"
                    title={inv.description || "Invoice"}
                  >
                    {inv.description || "Invoice"}
                  </div>
                </TableCell>
                <TableCell className="text-right font-medium">
                  {inv.amount}
                </TableCell>
                <TableCell className="text-right">
                  {statusBadge(inv.status)}
                </TableCell>
                <TableCell className="text-right">
                  <Button
                    variant="outline"
                    size="sm"
                    className="h-8 text-xs"
                    onClick={() =>
                      inv.invoiceUrl
                        ? window.open(
                            inv.invoiceUrl,
                            "_blank",
                            "noopener,noreferrer",
                          )
                        : onDownload?.(inv.id)
                    }
                    aria-label={`Download invoice ${inv.id}`}
                  >
                    <Download className="h-3.5 w-3.5" />
                    Download
                  </Button>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </CardContent>
    </Card>
  );
}

"use client";

/**
 * <PaymentMethodList /> — display saved payment methods.
 *
 * Mutations (add, remove, set default) go through the Stripe Customer
 * Portal. This component is read-only and points users at the portal
 * for any changes.
 */
import { Card, CardContent, CardHeader, CardTitle } from "@dollhousestudio/ui/components/card";
import { Badge } from "@dollhousestudio/ui/components/badge";
import { cn } from "@dollhousestudio/ui/lib/utils";
import { CreditCard, Wallet } from "lucide-react";
import { CustomerPortalButton } from "./customer-portal-button";

export interface PaymentMethodListItem {
  id: string;
  paymentMethodType: string;
  brand?: string;
  last4: string;
  expMonth: number;
  expYear: number;
  wallet?: string;
  isDefault: boolean;
}

export interface PaymentMethodListProps {
  paymentMethods: PaymentMethodListItem[];
  className?: string;
  title?: string;
  loading?: boolean;
}

export function PaymentMethodList({
  paymentMethods,
  className,
  title = "Payment methods",
  loading,
}: PaymentMethodListProps) {
  return (
    <Card className={cn("w-full", className)}>
      <CardHeader className="flex flex-row items-start justify-between gap-4">
        <CardTitle className="text-lg font-medium">{title}</CardTitle>
        <CustomerPortalButton size="sm" showIcon={false}>
          Add / edit
        </CustomerPortalButton>
      </CardHeader>
      <CardContent className="space-y-3">
        {loading && (
          <div className="py-6 text-center text-sm text-muted-foreground">
            Loading…
          </div>
        )}
        {!loading && paymentMethods.length === 0 && (
          <div className="py-6 text-center text-sm text-muted-foreground">
            No payment methods yet — add one via the portal.
          </div>
        )}
        {paymentMethods.map((pm) => {
          const brand = pm.brand
            ? pm.brand.charAt(0).toUpperCase() + pm.brand.slice(1)
            : pm.paymentMethodType;
          const Icon = pm.wallet ? Wallet : CreditCard;
          return (
            <div
              key={pm.id}
              className="flex items-center justify-between rounded-lg border p-3"
            >
              <div className="flex items-center gap-3">
                <div className="rounded-md border bg-background p-2">
                  <Icon className="h-4 w-4" />
                </div>
                <div className="flex flex-col">
                  <div className="flex items-center gap-2">
                    <span className="font-medium">
                      {brand} •••• {pm.last4}
                    </span>
                    {pm.isDefault && (
                      <Badge variant="secondary" className="text-[10px]">
                        Default
                      </Badge>
                    )}
                  </div>
                  {pm.expMonth && pm.expYear && (
                    <span className="text-xs text-muted-foreground">
                      Expires {String(pm.expMonth).padStart(2, "0")}/
                      {String(pm.expYear).slice(-2)}
                    </span>
                  )}
                </div>
              </div>
            </div>
          );
        })}
      </CardContent>
    </Card>
  );
}

"use client";

/**
 * <PricingTable /> — Parcae-wired pricing table.
 *
 * Forked from billingsdk's pricing-table-one (dodopayments/billingsdk,
 * MIT). Theming stripped to the project's default shadcn tokens. Plans
 * are fed live from `useQuery(Product.where({ active: true }))`.
 */
import { Check, Zap } from "lucide-react";
import { useState, useId } from "react";
import { motion, AnimatePresence } from "motion/react";
import { cva, type VariantProps } from "class-variance-authority";

import { Badge } from "@dollhousestudio/ui/components/badge";
import { Button } from "@dollhousestudio/ui/components/button";
import { Label } from "@dollhousestudio/ui/components/label";
import { RadioGroup, RadioGroupItem } from "@dollhousestudio/ui/components/radio-group";
import { Separator } from "@dollhousestudio/ui/components/separator";
import { cn } from "@dollhousestudio/ui/lib/utils";

import type { Plan } from "../lib/billing-transformers";

const sectionVariants = cva("py-16 md:py-24", {
  variants: {
    size: {
      small: "py-6 md:py-12",
      medium: "py-10 md:py-20",
      large: "py-16 md:py-32",
    },
  },
  defaultVariants: { size: "medium" },
});

const cardVariants = cva(
  "flex w-full flex-col rounded-lg border text-left h-full transition-all duration-300 p-6",
  {
    variants: {
      highlight: {
        true: "bg-muted",
        false: "",
      },
    },
    defaultVariants: { highlight: false },
  },
);

export interface PricingTableProps extends VariantProps<
  typeof sectionVariants
> {
  plans: Plan[];
  title?: string;
  description?: string;
  className?: string;
  /** Called with the selected Plan — do your checkout there. */
  onPlanSelect?: (plan: Plan, interval: "monthly" | "yearly") => void;
  defaultInterval?: "monthly" | "yearly";
}

export function PricingTable({
  plans,
  title = "Pricing",
  description = "Transparent pricing with no hidden fees.",
  onPlanSelect,
  defaultInterval = "monthly",
  size,
  className,
}: PricingTableProps) {
  const [isAnnually, setIsAnnually] = useState(defaultInterval === "yearly");
  const uniqueId = useId();

  const yearlyDiscount = plans.length
    ? Math.max(
        ...plans.map((p) => {
          const m = parseFloat(p.monthlyPrice);
          const y = parseFloat(p.yearlyPrice);
          if (isNaN(m) || isNaN(y) || m === 0) return 0;
          return Math.round(((m * 12 - y) / (m * 12)) * 100);
        }),
      )
    : 0;

  return (
    <section className={cn(sectionVariants({ size }), className)}>
      <div className="container relative p-0 md:p-4">
        <div className="mx-auto flex max-w-7xl flex-col gap-6">
          <div className="flex flex-col gap-4">
            <h2 className="text-pretty font-bold text-4xl lg:text-5xl">
              {title}
            </h2>
          </div>

          <div className="flex flex-col justify-between gap-5 md:flex-row md:gap-10">
            <p className="max-w-3xl text-lg text-muted-foreground lg:text-xl">
              {description}
            </p>
            <div className="flex h-11 w-fit shrink-0 items-center rounded-md bg-muted p-1 text-lg">
              <RadioGroup
                defaultValue={isAnnually ? "annually" : "monthly"}
                className="h-full grid-cols-2"
                onValueChange={(v) => setIsAnnually(v === "annually")}
              >
                <div className="h-full rounded-md transition-all has-[button[data-state=checked]]:bg-background">
                  <RadioGroupItem
                    value="monthly"
                    id={`${uniqueId}-monthly`}
                    className="peer sr-only"
                  />
                  <Label
                    htmlFor={`${uniqueId}-monthly`}
                    className="flex h-full cursor-pointer items-center justify-center px-4 text-sm font-semibold text-muted-foreground transition-all peer-data-[state=checked]:text-primary hover:text-foreground"
                  >
                    Monthly
                  </Label>
                </div>
                <div className="h-full rounded-md transition-all has-[button[data-state=checked]]:bg-background">
                  <RadioGroupItem
                    value="annually"
                    id={`${uniqueId}-annually`}
                    className="peer sr-only"
                  />
                  <Label
                    htmlFor={`${uniqueId}-annually`}
                    className="flex h-full cursor-pointer items-center justify-center gap-1 px-4 text-sm font-semibold text-muted-foreground transition-all peer-data-[state=checked]:text-primary hover:text-foreground"
                  >
                    Yearly
                    {yearlyDiscount > 0 && (
                      <span className="ml-1 rounded border border-primary/20 bg-primary/10 px-2 py-0.5 text-xs font-medium text-primary">
                        Save {yearlyDiscount}%
                      </span>
                    )}
                  </Label>
                </div>
              </RadioGroup>
            </div>
          </div>

          <div className="flex w-full flex-col items-stretch gap-6 md:flex-row">
            {plans.map((plan, index) => (
              <motion.div
                key={plan.id}
                layout
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ duration: 0.3, delay: index * 0.1 }}
                className={cn(cardVariants({ highlight: plan.highlight }))}
              >
                <Badge className="mb-6 w-fit">{plan.title}</Badge>

                <AnimatePresence mode="wait">
                  <motion.div
                    key={isAnnually ? "year" : "month"}
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, y: -10 }}
                    transition={{ duration: 0.2 }}
                  >
                    <span className="text-4xl font-medium">
                      {parseFloat(
                        isAnnually ? plan.yearlyPrice : plan.monthlyPrice,
                      ) >= 0 && <>{plan.currency}</>}
                      {isAnnually ? plan.yearlyPrice : plan.monthlyPrice}
                    </span>
                    <p className="text-muted-foreground">
                      per {isAnnually ? "year" : "month"}
                    </p>
                  </motion.div>
                </AnimatePresence>

                <Separator className="my-6" />

